const input = $input.first().json;
const body = input.body || input;

// 判断来源
const isRetell = body.event === 'call_analyzed';
const isTally = !isRetell && body.data && body.data.fields;

if (isRetell) {
  const call = body.call;
  const analysis = call.call_analysis;

  return {
    source: 'retell',
    call_id: call.call_id,
    transcript: call.transcript,
    summary: analysis.call_summary,
    sentiment: analysis.user_sentiment,
    call_successful: call.call_successful,
    duration_seconds: call.duration_ms / 1000,
  };

} else if (isTally) {
  const fields = body.data.fields;
  const getField = (label) => fields.find(f => f.label === label);
  const getDropdownText = (label) => {
    const field = getField(label);
    if (!field) return '';
    const selectedId = field.value[0];
    const option = field.options.find(o => o.id === selectedId);
    return option ? option.text : '';
  };

  return {
    source: 'tally',
    patientName: getField('Patient Name')?.value || '',
    phone: getField('Phone Number')?.value || '',
    email: getField('Email')?.value || '',
    appointmentDate: getField('Appointment Date')?.value || '',
    appointmentTime: getDropdownText('Appointment Time'),
    service: getField('Doctor/Service')?.value || '',
  };
}

